func TestEnumTypesAnimalOneAnimal(t *testing.T) {
	t.Run("NewFromString_cat", func(t *testing.T) {
		t.Parallel()
		val, err := NewTypesAnimalOneAnimalFromString("cat")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, TypesAnimalOneAnimal("cat"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewTypesAnimalOneAnimalFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewTypesAnimalOneAnimalFromString("cat")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

